#include <stdio.h>
#include <string.h>

int isRepetitionFree(char *num) {
    int len = strlen(num);
    for (int i = 0; i < len; i++) {
        for (int j = i + 1; j < len; j++) {
            if (num[i] == num[j]) return 0;
        }
    }
    return 1;
}

void findNextRepetitionFree(char *num) {
    int len = strlen(num);
    int i = len - 1;
    while (i >= 0 && num[i] == '9') i--;
    if (i >= 0) {
        num[i]++;
        for (int j = i + 1; j < len; j++) num[j] = '0';
    } else {
        num[0] = '1';
        for (int j = 1; j <= len; j++) num[j] = '0';
    }
    while (!isRepetitionFree(num)) findNextRepetitionFree(num);
}

int main() {
    char num[1000];
    scanf("%s", num);
    findNextRepetitionFree(num);
    printf("%s\n", num);
    return 0;
}

