    if (i >= 0) {
        num[i]++;
        for (int j = i + 1; j < num.length(); j++) num[j] = '0';
    } else {
        num = "1" + string(num.length(), '0');
    }
    while (!isRepetitionFree(num)) findNextRepetitionFree(num);
