import java.util.Scanner;
public class Main {
    public static boolean isRepetitionFree(String num) {
        for (int i = 0; i < num.length(); i++) {
            for (int j = i + 1; j < num.length(); j++) {
                if (num.charAt(i) == num.charAt(j)) return false;
            }
        }
        return true;
    }

    public static void findNextRepetitionFree(String num) {
        int i = num.length() - 1;
        while (i >= 0 && num.charAt(i) == '9') i--;
        if (i >= 0) {
            num = num.substring(0, i) + (char)(num.charAt(i) + 1) + new String(new char[num.length() - i - 1]).replace('\0', '0');
        } else {
            num = "1" + new String(new char[num.length()]).replace('\0', '0');
        }
        while (!isRepetitionFree(num)) findNextRepetitionFree(num);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        String num = scanner.next();
        findNextRepetitionFree(num);
        System.out.println(num);
    }
}

