def is_repetition_free(num):
    for i in range(len(num)):
        for j in range(i + 1, len(num)):
            if num[i] == num[j]: return False
    return True

def find_next_repetition_free(num):
    i = len(num) - 1
    while i >= 0 and num[i] == '9': i -= 1
    if i >= 0:
        num = num[:i] + chr(ord(num[i]) + 1) + '0' * (len(num) - i - 1)
    else:
        num = '1' + '0' * len(num)
    while not is_repetition_free(num): find_next_repetition_free(num)
    return num

